import React from 'react';

function Education({ data }) {
  if (!data) return null;

  return (
    <section id="education" className="py-12 md:py-16 bg-gray-50">
      <div className="max-w-2xl mx-auto px-4">
        <div className="bg-white rounded-2xl shadow-lg p-8">
          <h2 className="text-2xl font-bold text-gray-900 mb-6">Education</h2>
          <div className="space-y-6">
            {data.map((edu) => (
              <div key={edu.id} className="pb-6 border-b border-gray-200 last:border-b-0">
                <div className="flex items-start gap-4">
                  <div className="w-12 h-12 bg-gradient-to-br from-purple-400 to-purple-600 rounded-lg flex items-center justify-center text-white text-lg flex-shrink-0">
                    🎓
                  </div>
                  <div>
                    <h3 className="text-lg font-bold text-gray-900">{edu.degree}</h3>
                    <p className="text-blue-600 font-semibold mt-1">{edu.institution}</p>
                    <p className="text-sm text-gray-600 mt-2">{edu.period}</p>
                    {edu.details && <p className="text-sm text-gray-600 mt-1">{edu.details}</p>}
                    {edu.location && <p className="text-sm text-gray-500 mt-1">{edu.location}</p>}
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
}

export default Education;
